from sqlalchemy import Column, Integer, String, JSON, DateTime, BigInteger;
from sqlalchemy.ext.declarative import declarative_base;

Base = declarative_base();

class TelemetryData(Base):
    __tablename__ = 'telemetry';
    id = Column(BigInteger, primary_key=True);
    device_id = Column(String(64), index=True);
    gan_temp = Column(Integer);
    bus_state = Column(JSON);
    timestamp = Column(DateTime, index=True);

class CapabilityToken(Base):
    __tablename__ = 'capability_tokens';
    token_hash = Column(String(128), primary_key=True);
    bitmask = Column(BigInteger);
    expires_at = Column(DateTime);

